LUES (2400299920, 'ADEMIR RIBEIRO DE PAULA', 'GERENTE PAA', '2024-04-15 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010442-78.2024.5.15.0054', NULL, NULL, '01', 'SERTAOZINHO', 'SP', '2024-04-17 00:00:00', 'EX-FUNCIONARIOS', 'VITOR MONAQUEZI FERNANDES ', 'Aguarda realizaçăo de audięncia. PROCEDENTE. Năo aplicou reforma, năo falou do par 3 da claus 11. Indeferiu PLR e acolheu cartoes. ED pelo§3ş, rejeitado. Acolhido do Autor p; rejeitar PLR. RO por ambos. Provido nosso p/ IMPROC (cc pelo 224 - năo declarou a IMPROC, só excluiu a verba, mas achei melhor nao apresentar ED). Na CRRR, falar da limitaçao dos valores.', '7Ş e 8Ş, com compensaçao - IMPROCEDENTE', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
