LUES (2300233000, 'ALEF ROBERTO XAVIER', 'CAIXA - GERENTE ASSISTENTE - GERENTE RELACIONAMENTO PRIME', '2023-03-14 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010370-11.2023.5.15.0092', NULL, 'Joăo Alberto - 10Ş Câmara', '05', 'CAMPINAS', 'SP', '2023-03-27 00:00:00', 'EX-FUNCIONARIOS', 'NILO DA CUNHA JAMARDO BEIRO', 'Aguarda realizaçao de audięncia. PROCEDENTE. Perdeu sal subs, PLR, DM. Cartoes ok. Năo colocou o desvio no dispositivo nem falou do §3ş. Vamos de ED. RO por ambos. Providos do Banco p/ mandar reabrir a instr. Apresentamos ED pelo §3ş e possibilidade de năo reabrir. Rejeitado e aplicada multa. Aguardamos reabertura da instruçăo. Nova sentença igual anterior, năo questionarei cl 11 §3 em ED, pois já levamos má-fé no TRT e juiz já negou a matéria no primeiro ED, entendo ser arriscado (Van). RO por ambos.  ', 'Desvio de funçao, 7a e 8a, comp ok. ANULADA - Multa má-fé ED no TRT + Desvio de funçao, 7a e 8a (comp ok)', 'TRT', 'N/D', NULL, 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, 'valor muito baixo', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', 'S', NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
