LUES (2500352647, 'ALEX FERNANDO FRANCISCO', 'GERENTE DE CONTAS PESSOA JURIDICA - GERENTE  ADMINISTRATIVO ', '2025-05-08 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010514-09.2025.5.15.0029', NULL, NULL, '01', 'JABOTICABAL', 'SP', '5/13/2025', 'EX-FUNCIONARIOS', 'DANIEL ALEX MICHELON ', 'Aguarda realizaçăo de audiencia. Foi p/ perícia. Laudo atestou doença, mas sem nexo! PROCEDENTE. Perdeu acúmulo, VR, PDE, férias, IJ, cartoes ok, cc (224), HE pós 8a, KM, doença e relacionados, aux ali, PPP, dif aposentadoria, conversao de pedido de dem em resc indireta. ED por ambos, rejeitados. RO por ambos (Thelma Helena - 9Ş Câmara). ', '14010, dif HE (mes cartao), DM (transp valor - 3k), PLR prop, dev contrib sindical, multa CCT, ', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, 'Ofereci 40k em 30/7 (max 68.6). Em 4/8 passei proposta p/ Lais. Informei em 6/8 Lais por cel que a proposta foi retirada. Voltou menor na MT 90. Liguei p/ Lais em 1/9 e nao atendeu. Insisti em 4/9. SENTENÇA.', NULL, 'Arthur Wpp (16) 99796-4346 / Lais (16)99963-2023', NULL, 'Nunca retornam', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', NULL, NULL, 'Sim', NULL, NULL, 'S', 'Sim', 'Sim', NULL, NULL, 'Sim', 'NULIDADE DO PEDIDO DE DEMISSĂO E DO MOTIVO PARA RESCISĂO INDIRETA + VERBAS RESCISÓRIAS; INDENIZAÇĂO SUBSTITUTIVA Ŕ COMPLEMENTAÇĂO PARA APOSENTADORIA E POSSÍVEL RETIFICAÇĂO PPP''S; contribuiçăo assistencial DEVOLUÇĂO', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
