LUES (2400496516, 'ALEX JUNIOR DA SILVA', 'GERENTE DE CONTAS PESSOA FÍSICA - GERENTE ASSISTENTE - SUPERVISOR ADMINISTRATIVO ', '2024-06-05 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010763-66.2024.5.15.0102', NULL, NULL, '02', 'TAUBATE', 'SP', '2024-06-10 00:00:00', 'EX-FUNCIONARIOS', 'EVANDRO PREVEDELLO', 'Aguarda realizaçăo de audięncia UNA. PROCEDENTE. Perdeu cc, vr, comissoes e PDE. Vamos de ED, nao providos. Vamos de RO (Claudinei Zapata Marques - 8Ş Câmara). Năo provido Reclamante e nosso só p/ HÁ. ED por erro material. Novo ED nosso pq só julgaram do rct (năo provido). Provido nosso.', 'He pos 8 e IJ', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, '(năo esta na PPS) liq -20%=67.682  + 10%: ', NULL, 'Calcs 105k. Perdi o o historico pq a planilha nao salvou minhas alteraçoes. No final, ofereci 67 liq + 6.7 hon em 15/8. Nao aceitou em 20/8/25. Calcs distantes. Renovei a proposta em 16/12/25.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, 'PDE', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
