LUES (2300970494, 'ALEXANDRE PEDRAO', 'GERENTE AGENCIA - GERENTE NEGOCIOS PJ III - GERENTE DE CONTAS PESSOA JURÍDICA ', '2023-11-14 00:00:00', 'BANCO BRADESCO S.A.', '-', '0012015-65.2023.5.15.0094', NULL, NULL, '07', 'CAMPINAS', 'SP', '2023-11-17 00:00:00', 'EX-FUNCIONARIOS', 'CELSO FERRAREZE', 'VERBA DE REPRESENTAÇĂO. Aguarda realizaçăo de audięncia UNA. Juíza aplicou os critérios do banco para pgto de Verba de representaçăo e viu q o banco năo cumpriu o q estipulou quando o Reclamante era gerente geral (13 meses), condenando nesse período. Assim, a interrup presc e a aplica da reforma nao fara diferença na condenaçao. Pedirei dispensa. Sergio mandou apresentar RO, apresentei só da % de ha, pois a sentença acolheu nossa tese. ED pelo Autor, provido mas nada mudou. RO por ambos. Nao providos. RR dispensado. RR e AIRR pelo Autor,', 'Presc 14.010, dif Verba de representaçăo ', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
