LUES (2100885604, 'ALINE TORREAO DA SILVA', 'ANALISTA SUPORTE OPERACOES JR', '2021-10-07 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011376-06.2021.5.15.0001', NULL, NULL, '1', 'CAMPINAS', 'SP', NULL, 'EX-FUNCIONARIOS', 'MARILU CRISTINA RIBERO LEFOSSE ', 'Aguarda realizaçăo de audięncia INICIAL em 20/5/22. Banco Bradesco excluído da lide, pois năo foi empregador. Banco Bradesco Financiamentos incluído. Aguarda INSTR. No dia da instr, juíza reconheceu nossa tese de presc bienal e chamou ŕ sentença. EXTINTO por prescriçao. ED da Autora, nao provido. RO por ambos (Banco só pela presc da 14.010). TRT reverteu a prescriçăo e mandou voltar, instruir e julgar. PROCEDENTE. Aceitou cartoes. Fomos de ED pelo §3ş, rejeitados. RO por ambas. Provido do banco para IMPROC (cc §3). RR rct. Vamos de RR condicionado pela prescriçăo. Denegado RR. Ver se vamos de AIRR pq nosso é adesivo.', 'PRESSCRITO - 7a e 8a (com comp) - IMPROCEDENTE (§3ş)', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
