LUES (2200896215, 'AMINA VALERIA PEDROSO FRANCO', 'GERENTE DE CONTAS PESSOA JURÍDICA ', '2022-10-25 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010521-37.2022.5.15.0148', NULL, NULL, '01', 'ITARARE', 'SP', '2022-10-28 00:00:00', 'EX-FUNCIONARIOS', 'CELSO FERRAREZE', 'Aguarda realizaçăo de audięncia UNA. Deferiu tudo. ED pelo banco, rejeitado. RO pelo Banco, adesivo pela Autora. Proveu para reconhecer cc, excluir VR, ajustar IJ e 384 ŕ reforma. RR pela correçao - denagado e  pela Autora, processado para discutir aplicaçăo da reforma. AIRR dispensado, apresentado pela Autora. ', 'verba de representaçăo, he pos 6, 384, he em reunioes, cursos e deslocamento,  férias, DM (20k), HÁ (10)', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'bruto com hon: 70.030,21', '100k + hon', 'Ofereci 45k + hon em 8/8 por tel e e-mail. Depois 53k bruto + hon. Nao quis mais saber. Em 2/5, perguntou se majoramos a proposta. Em 10/5, mandei 55k liq (50 + 5 hon)', NULL, 'Ferrareze CTB - Franciele - (41) 3233-0784 ', 'N', 'INICIAR', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', 'Sim', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, 'Curso CPA 20', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
