LUES (2300798687, 'ANA CLAUDIA ARENA', 'GERENTE DE CONTAS PESSOA FÍSICA- GERENTE ASSISTENTE', '2023-09-05 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011751-09.2023.5.15.0010', NULL, '8Ş Câmara', '01', 'RIO CLARO', 'SP', '2023-09-15 00:00:00', 'EX-FUNCIONARIOS', 'CELSO FERRAREZE', 'VERBA DE REPRESENTAÇĂO. Aguarda realizaçăo de audięncia. PROCEDENTE. ED sobre parâmetros. Năo provido. Vamos de RO (8Ş Câmara - Erodite). Provido para improc!', 'VERBA DE REPRESENTAÇĂO - IMPROCEDENTE', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Improc', NULL, 'enviei 70k em 4/10/23  p/ Sidneia (apenas para o q já recebemos de Verba de representaçăo). Retirei a proposta em 23/10/23. Banco retirou a proposta, mas como Sid năo tinha me respondido, nada fiz. Em 11/11, com nova proposta, mandei novamente em p/ outras advs o valor de 70k. Em 7/1, mandei 200k para os 2. Cobrei em 14/01, 22. Sem resposta, Banco diminui a proposta total de 340k para 103k. Em 17/02, falei que a proposta foi retirada. A pedido, ofereci 80k b em 4/7/25. RETIRADO. Ferreareze informado em 28/7. SENTENÇA', NULL, 'e-mail', 's', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
