LUES (2400268320, 'ANDRE RAPHAEL OLIVEIRA DO NASCIMENTO', 'GERENTE ASSISTENTE - CAIXA - ESCRITURARIO', '2024-04-03 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010566-10.2024.5.15.0071- CumPrSe: 0011446-65.2025.5.15.0071', NULL, NULL, '01', 'MOGI GUACU', 'SP', '2024-04-11 00:00:00', 'EX-FUNCIONARIOS', 'ALAN HONJOYA', 'Aguarda realizaçăo de audięncia. PROCEDENTE. Cartoes ok. RO por ambos. RO rcte provido em parte para deferir ADC 58, excluir h. adv p/ nós, majorou DM (15K), he e reflexos. RO Banco: deferiu compensaçăo, limitou condenaçăo mul cct, excluiu período de férias em dobro. RR dispensado. RR e AIRR autor. Denegados. CumPrSe: vamos man calcs rct. Foi p/ perícia. Impugnamos, aceita e homologados calcs com ordem de garantia da exe.', 'HE pos 6Ş, comp ok, IJ, desvio 25%, IJ 15, venda férias, dif PLR, multa CCT, DM (15k), HÁ (5%) ', 'TST/ Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'risco: 36.415 / alçada: 29.231 B+ hon', NULL, 'Oferecido 25K em audięncia, quis 400k. Após sentençca, como năo deu compensaçăo, năo vale a pena tentar. Mandaram e-mail perguntando e eu respondi 30k e depois vi q mudou. Mas năo vao aceitar mesmo. Acordao.  Ofereci 25k b em 15/7. Cobrei em 4/8, disse q nao quer. Em 8/9, mandei 26k liq+ 5% hon', NULL, NULL, 'n', 'INICIAR', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
