LUES (2300809462, 'ANDRE RICARDO DE GOES JORDAO - Re por instr (ver andamento)', 'GERENTE DE CONTAS PESSOA JURÍDICA - FISICA - ', '2023-06-12 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011134-31.2023.5.15.0016', NULL, NULL, '02', 'SOROCABA', 'SP', '2023-09-25 00:00:00', 'EX-FUNCIONARIOS', 'ANTONIO MILLER MADEIRA', 'Aguarda realizaçăo de audięncia UNA. PROCEDENTE em parte. Perdeu cc, IJ, DM, cartoes ok. Vou de ED contra os apontamentos em replica, tentando a improc. Năo providos. RO por ambos. Provido do rct p/ anular a sentença e mandar ouvir as partes. Aguarda nova instr. Orientar adv a treinar perfeitamente o preposto, pq é o unico jeitoda gente perder', 'Dif he năo pagas ', 'Vara do Trabalho', 'BAIXADA', '00:00:00', '14:00:00', NULL, NULL, NULL, NULL, NULL, '900.000,00 bruto + 10% de honorários', 'Ana oferecerá 100k. Oferecido 100k. Năo aceitou a proposta a pretensăo é R$ 900.000,00 bruto + 10% de honorários. Majorei a proposta para 200k apresentou contraproposta de R$ 850 mil brutos  + 10%. SENTENÇA de 12.5k e acordao anulou p/ ouvir rct e rcd. Após isso, a pedido, ofereci 50k liq. Querem 750k b. encerrado   ', NULL, 'Ruth - e-mail: acordos@bbmd.adv.br', 'n', 'ENCERRADO', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
