LUES (2200380917, 'ANDRE ROBERTO ALVES DOS SANTOS', 'GERENTE DE CONTAS PESSOA JURÍDICA III', '2022-05-04 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010619-57.2022.5.15.0007', NULL, NULL, '1', 'AMERICANA', 'SP', NULL, 'EX-FUNCIONARIOS', 'NILO DA CUNHA JAMARDO BEIRO', 'Aguarda realizaçăo de INICIAL em 12/07/22. INSTR para 23. Aguarda sentença. IMPROCEDENTE. RO do Autor, provido apenas para aceitar a interrupçao da prescriçao, ou seja, manteve a IMPROC. ED pelo Autor, rejeitados. RR e AIRR pelo Autor. Denegados! Agravo pelo Autor.', 'IMPROCEDENTE', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
