LUES (2400685170, 'ARIADNE CRISTINA GIMENES', 'ESPECIALISTA INVESTIMENTOS I - GERENTE CONTAS PESSOA FISICA I ', '2024-08-06 00:00:00', 'BANCO BRADESCO S.A.', '-', '0012608-14.2024.5.15.0077', NULL, NULL, '01', 'INDAIATUBA', 'SP', '2024-08-23 00:00:00', 'EX-FUNCIONARIOS', 'DELMAR CECCON JUNIOR ', 'ATIVA - Aguarda realizaçăo de aud. Correndo na outra - APOS TRÂNSITO, INFORMAR BANCO P/ DISPENSA DO AUTOR - ACORDO', '7Ş e 8Ş (comp ok), pensăo mensal de 2,28% da juntada do laudo enquanto durar a incapacidade, DM (15k doença), plano saude até a recuperaçao,  rescisăo indireta a partir de 30/1/25 - ACORDO', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, '150k b (rel)', '135k + 10% para quitaçao de tudo', 'TEM OUTRO PROCESSO. Em audięncia foi oferecido 140k e advogado ficou de retornar com contraproposta, pois ela ta ativa. Banco retirou a proposta e quando o advogado me ligou em 16/01 o informei. Depois Banco liberou 7k, mas nem informei pois irrisório. NA MT 71, baixou p/ 6.6. Ofereci 6.500 em 31/3. Nao aceitou. Retirada na MT 90. SENTENÇA. Ofereci 90+10 em 12/01. Em 16/1, submeti relatório. Ok em 29/01', '150k', 'Aline - whatsapp / Delmar - (61) 9 8156-6483', 'n', 'Aguarda homologaçăo', '2026-02-13 00:00:00', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', 'processado');
