LUES (2500165782, 'BRUNO CEZAR CURSINO RAMOS', 'GERENTE ADMINISTRATIVO - GERENTE ADMINISTRATIVO  UNIDADE - SUPERVISOR ADMINISTRATIVO I ', '2025-02-28 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010371-15.2025.5.15.0063', NULL, NULL, '01', 'CARAGUATATUBA', 'SP', '2025-03-07 00:00:00', 'EX-FUNCIONARIOS', 'EVANDRO PREDEVELLO ', 'Aguarda realizaçăo de audięncia. PROCEDENTE. RO por ambos (11Ş Cam)', 'PDE, VR, HE e IJ - ACORDO', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, '199.700 - RELATÓRIO', '440k / 210+10', 'Ofereci 70k em 3/4. 100k em 22/4. Renovei com Michele em 12/5. Cobrei em 19/5. Mantive 100k em 21/5. Sem interesse. SENTENÇA. Ofereci 150k +10% em 18/8. Em 27/8, 180k b + 10% hon como máximo. Em 29/8 mandei o líquido. ', 199500, 'Fernanda - PTZ SP', NULL, 'FECHADO', '2025-10-08 00:00:00', NULL, NULL, 'SIM - falta const Fi apenas', NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 's', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 's', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
