LUES (2300823531, 'BRUNO EMILIANO', 'GERENTE DE CONTAS PESSOA JURÍDICA - FISICA - SUPERVISOR ADMINISTRATIVO ', '2023-09-13 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011640-86.2023.5.15.0022', NULL, NULL, '01', 'MOGI MIRIM', 'SP', '2023-09-25 00:00:00', 'EX-FUNCIONARIOS', 'CAROLINE ALESSANDRA ZAIA  ', 'Aguarda realizaçăo de audięncia. PROCEDENTE. Disse que rcte năo tinha confiança, mas negou 7 e 8 por causa da CCT, perdeu km. Vamos de ED pelo § 3ş da CCT. Nao provido. RO do Autor. Năo provido (mantido 224). RR autor.', 'DM (35k)', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 28671, '200k', 'Ofereci 20k em 7/4. Quer 200k. Encerrado. ACORDAO. Ofereci 28k liq em 9/12/25. Se der de aceitar peço calcs e, se precisar, relatório. Cobrei em 12/12, 18/12. Em 19/12, disse q nao aceitou. Em 5/1/26 pedi cpp. Insisti em 20/1.', NULL, 'Caroline Zaia - e-mail', NULL, 'Aguarda resposta', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
