LUES (2300162775, 'BRUNO GAROFANI', 'GERENTE DE CONTAS PESSOA FÍSICA - ASSISTENTE - SUPERVISORA - CAIXA', '2023-02-09 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010142-98.2023.5.15.0136', NULL, NULL, '01', 'PIRASSUNUNGA', 'SP', '2023-03-02 00:00:00', 'EX-FUNCIONARIOS', 'JOSE HENRIQUE MANZOLI SASSARON ', 'Aguarda realizaçăo de INICIAL. Aguarda INSTR. Sentença negou 7a e 8a, PLR prop, dev contr negocial, add transf, km e dm. ED pois năo falou dos descontos sobre o vale-cultura. Acolhidos os nossos e do Reclamante. Ambos apresentaram RO. RR dispensado. ED pelo autor, acolhidos apenas para fixar correçao dos DM pela sumula 439. Novo ED pelo Autor, acolhidos apenas para beneficar o banco. RR pelo Autor, denegado. Após ED, aceito. Denegado no TST. AgInterno.', 'Dif de he, IJ 15, sal subs, vale-cultura, multas CCT, há (15%), ADC sem juros, JG', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Bruto com hon: 23.897,72                                  Liq  com hon: 23.070,06                              desagil 20%: 18.456,04                                       ', NULL, 'Ainda nao iniciei. Começar oferecendo 12k. Disse que vai ver, tava sem cálculos. Chegamos aos 18k liq na audięncia.  Reclamante negou.', NULL, 'E-MAIL / tel. 19 3631-5347', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, 'S', 'S', NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', 'Vale-cultura/ dev contribuiçăo negocial', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
