LUES (2300228153, 'CARLA CRISTINA AFFONSO DOS SANTOS', 'CAIXA', '2023-03-22 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010872-18.2025.5.15.0079', NULL, NULL, '02', 'ARARAQUARA', 'SP', '2023-03-24 00:00:00', 'EX-FUNCIONARIOS', 'ERICSON CRIVELLI', 'Aguarda realizaçao de audięncia UNA. Procedente. Fomos de ED, rejeitados. RO só do Banco. Provido em parte para limitar IJ 15 aos dias de he e equip pelo tempo que laboraram na mesma agencia. ED por todos, năo providos. RR dispensado por Russo, apresentado pela Autora para nao aplicar a reforma. Aceito e aguarda julgamento. Negado seguimento no TST pelo tema 23. TRANSITOU. Calcs rct: 60k. Vamos impugnar.', 'Ij 15, equiparaçăo', 'Vara do Trabalho', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, '30k Liq', 'Ofereci 11k Liq em 28/11. Quer 30k Liq. Ajuizou outra açăo.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
