LUES (2100020079, 'CARLOS ALBERTO MOMESSO', 'GERENTE COMERCIAL I', '2020-12-02 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011724-83.2020.5.15.0025', NULL, NULL, '1', 'BOTUCATU', 'SP', NULL, 'EX-FUNCIONARIOS', 'ANDREZA BIANCHINI TRENTIN', 'Aguarda realizaçăo de audięncia INICIAL em 01/06/21. Deferido 30 dias para reapreentaçăo da defesa e juntada de documentos. Depois, até 15/09/21, quando ocorrerá  INICIAL. Determinada perícia. SEM NEXO CAUSAL! INSTR para 25/8/22 , Adiada pq tests năo conectaram audio. INSTR para 2023. IMPROCEDENTE. RO pelo Autor, năo provido! ED pelo Autor, nao provido. RR e AIRR pelo Autor. Denegados! Agravo interno.  ', 'IMPROCEDENTE', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
