LUES (2100600901, 'CELSO MATIELO', 'VIGILANTE', '2021-08-09 00:00:00', 'GP GUARDA PATRIMONIAL', 'BANCO BRADESCO S.A.', '0011088-29.2021.5.15.0043', NULL, NULL, '3', 'CAMPINAS', 'SP', NULL, 'TERCEIRIZADO', 'ANDERSON DE OLIVEIRA BARBOZA ', 'Aguarda realizaçăo de audięncia UNA em 25/01/23. Adiada sine die porque Reclamante ta com uma doença que acarreta perda de memoria. Vai comprovar e autos irăo a conclusao. Feito sobretado por 45 dias. Depois por mais 180. ACORDO com a GP. Suspenso em relaçao ao Banco. GP nao pagou e reabriu instr. Sentença condenou banco a resp subs pelo acordo. Vamos de ED, improcedentes. Vamos de RO. RO pelo rct pedindo hon sucumbenciais. Provido nosso p/ afastar resp pela multa! TRANSITOU. Văo usar nosso dep recursal p/ pagar o acordo e liberar o restante (valor do acordo: 5.500).', 'Accordo com a 1a Ré- nao cumprido. Resp subs pelo accordo', 'Vara', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
