LUES (2200099906, 'CRISTIANE NAREZI DA SILVA SANTOS ', 'ASSISTENTE DE COBRANÇA', '2021-09-09 00:00:00', 'FARIA LIMA INFORMACOES CADASTRAIS EIRELI - ME', 'BRADESCO FINANCIAMENTOS + 2', '0011232-33.2021.5.15.0130', NULL, NULL, '11', 'CAMPINAS', 'SP', NULL, 'TERCEIRIZADO', 'ERICK MARCOS RODRIGUES MAGALHAES', 'Determinada apresentaçăo de defesa em 30 dias (1/4). 1 e 2 năo apresentaram e mandaram citar novamente. Aguarda INSTR. Adiada por năo citaçao das 2 primeiras Reclamadas. Procedente em parte. Todos apresentaram ED, improvidos.  RO por todos. Provido só da Autora p/ aumetar condenaçao. RR dispensado. TRANSITOU. Apresentaram cálculos e foi p/ perícia. Homologados do perito e mandaram 1a e 2a rcd pagar. Se năo pagar, ai pediremos man aos calculista p/ liq ou EE. Citou ETS por edital.', 'Resp subs etc', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
