LUES (2200926750, 'CRISTINA BIONDI GOMES COELHO', 'GERENTE ADMINISTRATIVO ', '2022-10-03 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010814-91.2022.5.15.0120', NULL, NULL, '02', 'JABOTICABAL', 'SP', '2022-11-09 00:00:00', 'EX-FUNCIONARIOS', 'GIOVANA CRISTINA CAMPANA ALMEIDA ', 'Após audięncia inicial, aguarda realizaçăo de audięncia de INSTR. Laudo deu nexo de causalidade com incap parcial de 50%, porém, ela năo pede pensao, só dm de 28k. Juiz babaca năo instruiu, mandou juntar atas paradigmas e apresentar RF. PROCEDENTE. Perdeu acúmulo, PDE, Vale-trsnp, cc, cartoes ok. ED por nós, RO pela Autora. Nos multaram por ED protelatórios. Vamos de RO. Provida Autora p/ majorar DM de 10k p/ 25k e nosso p/ tirar multa de ED e adc 158. RR dispensado. RR e AIRR pela Autora. Denegados. TRANSITOU. Vamos apresentar cálculos.', 'IJ, DM (doença - 25k)', 'VARA', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'PPS (exe): 37.150', '40k', 'Ofereci 20k em 3/4. Em 23/5, ela pediu 42. Abri os calculos e ela vai pedir ao contador. Cobrei em 12/6, 28/6, 15/7. Năo aceita menos que 35k. Pelo wpp, perguntei se segue a mesma pretensao em 11/12/26. Pediu 39k. Mandei 37.500 em 17/12. Disse que năo quer por causa do prazo para pgto. Insisti em 20/01/26.', NULL, 'Natalia (16) 99739-8338', NULL, 'Aguarda resposta ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'sim', NULL, 'sim', 'sim', NULL, NULL, NULL, NULL, 'SIM', NULL, 'sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'PDE/vale transporte', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
