LUES (2200836660, 'DANIELA DOS SANTOS DIAS MEDEIROS', 'GERENTE DE CONTAS PESSOA JURÍDICA ', '2022-09-23 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011245-82.2022.5.15.0005', NULL, NULL, '01', 'BAURU', 'SP', '2022-10-07 00:00:00', 'EX-FUNCIONARIOS', 'RODRIGO NOVELINI INACIO', 'Reintegraçao liminar  por doença (burnout) negada. Aguarda realizaçăo de audięncia INICIAL. Determinada perícia médica, que năo constatou nexo de causalidade. Houve INSTR com oitva em 24/7/23 e la o juiz determinou nova pericia com psiquiatra. Perita nao marcou pericia e nomearm outro perito. Aguarda. PROCEDENTE. Perdeu deonça, estabildiade, reintegraçao, dispensa discrim, DM, cc, I 384, plano saude e PLR. ED nosso pelo valor sal subs. Aceitos. RO por ambos, provido apenas do Banco p/ deduzir HE nos periodos de substituiçao. RR dispensado. ED da Autora, nao provido. TRANSITOU. Rct apresentou calcs de 25.100. Impugnamos (6k).', 'Sal subs (3 meses), dev valores TRCT e HÁ (15)', 'Vara do Trabalho', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 5467, NULL, 'Ofereci 4.600 em 27/5. Cobrei em 12/6, 24/6. Em 30/6 pediu 24k. Questionei no mesmo dia os valores pedidos. Cobrei em 15/7. EM EXECUÇAO', NULL, 'e-mail', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'sim', NULL, NULL, NULL, NULL, 'sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'sim', 'sim', 'sim', NULL, 'sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'sim', 'sim', 'processado');
