LUES (2301083259, 'DEBORA ROSSI MAFRA', 'CAIXA - GERENTE ASSISTENTE - GERENTE CONTAS PESSOA FISICA ', '2023-12-19 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011816-81.2023.5.15.0146', NULL, NULL, '01', 'ORLANDIA', 'SP', '2023-12-26 00:00:00', 'EX-FUNCIONARIOS', 'ANDRE EVANGELISTA DE SOUZA ', 'DEFESA EM 15 DIAS. Devidaemnte apresentada. Reclamante concordou com os cartoes em audięncia. Audięncia cindida para ouvir testemunhas depois. PROCEDENTE. Perdeu cc, IJ, cartoes ok, acúmulo/desvio. Vamos de ED. Nao acolhidos. RO por ambas. Aceito nosso p/ tirar he. Russo vai de ED pela correçăo. ACORDO.', 'Dif de he, DM (80) - ACORDO', 'Vara do Trabalho', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, '165k liq', 'Ofereci 40k em 27/5 (mas se aceitarem, terá que ser por relatório). Ofereci 88k bruto em 9/6. Retirar depois. Pediram o valor líquido :/  Responder que retiraram a proposta, nao vai precisar pois tiraram as HE. Após acórdao, veieram cals de 95k (corrigidos).  Ofereci 88k liq=b.', '80 + 8', 'e-mail', NULL, NULL, '2025-10-26 00:00:00', NULL, 'nao pagaram O ACORDO (só tem acordo)', 'sim', NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
