LUES (1400142252, 'EDSON MENDES ', 'GERENTE AGENCIA', '2013-12-12 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010119-73.2013.5.15.0114', '0010411-14.2020.5.15.0114', NULL, '9', 'CAMPINAS', 'SP', NULL, 'EX-FUNCIONARIOS', 'CELSO FERRAREZE', 'Denegado seguimento ao RR (Autor: cc, validade cartőes, treinet, IJ, HA e IPCA/ Banco: art. 62 e nao 224 para GG) de ambas as partes. Partes apresentaram AI, ambos denegados. Autor apresentou Agravo regimental, desprovido. TRANSITOU. Exe Prov: Impugnamos os cálculos do rct. Aceitaram apenas em relaçăo ŕ correçăo, que mandou aplicar a ADC 58. Autor reapresentou cálculos sem ADC 58 e pediu reconsidereaçăo dessa decisăo. Juíza indeferiu e mandou arrumar os cálculos. Após nova apresentaçăo, homologou os do Autor. Na Exe prov, mandou o perito apresentar cálculos mesmo ja havendo calculos do rct homologado. Desconsiderou os cálculos anteriormente apresentados e homologou os do perito. AP pelas partes, provido do rct para deferir reflexos nas verbas rescisorias e do banco nao provido. RR e AIRR pelo Russo. Denegados. Na vara, perito vai readequar os cálculos.', '7a e 8a horas; horas após 8a, treinet, reflexos FGTS, TR, ADC 58', 'Vara do Trabalho', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Bruto c/ hon: 61.485                  Liq c/ hon: 61.430', NULL, 'Pedi pra Thay incluir na lista do TST. Ofereci 55k liq em 16/4. Cobrei em 12/5, 26/5', NULL, 'e-mail Katia', NULL, 'Nunca responde', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
