LUES (2300186331, 'FABIO CAZZO GONCALVES', 'GERENTE FINANCIAMENTOS I', '2023-02-08 00:00:00', 'BANCO BRADESCO FINANCIAMENTOS S.A', 'BANCO BRADESCO S.A.', '0010201-89.2023.5.15.0135 CumpPrSen: 0013047-45.2024.5.15.0135', NULL, NULL, '04', 'SOROCABA', 'SP', '2023-03-08 00:00:00', 'EX-FUNCIONARIOS', 'FABYO LUIZ ASSUNCAO', 'Aguarda realizaçăo de audięncia. PROCEDENTE. Vamos de ED. RO pelo Banco e adesivo pelo Autor. Provido apenas o nosso p/ comp e tirar o valor compensado da base de calcs das HE. RR dispensado. ED pelo rct. Denegado. RR e AIRR rct. CumpPrSen: devemos contestar cálculos. Concordamos. Como os cálculos seguiram a sentença que nao determinou ADC 58, juiz mandou rct reapresentar cálculos e nós nos manifestarmos de novo, concordando. Homologados os do rct. Garantimos. Uniăo apresentou ISL, mas por ser prov, juíza mandou aguardar o trânsito. ', 'Resp sol, HE pós 6a (COMP OK), jornada inicial, IJ 30', 'TST/ Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Liq c/ hon: 162k                                      Deságil: 129.650 (valor max LIQ p/ acordo)', NULL, 'Assunçao e năo deu compensaçao. Năo vale iniciar', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
