LUES (2400027071, 'FELIPE REIS DE MELO', 'OPERADOR DE TELEATENDIMENTO', '2024-01-12 00:00:00', 'AEC CENTRO DE CONTATOS S/A', 'BANCO BRADESCO S/A', '1000028-62.2024.5.02.0087', NULL, NULL, '16', 'SAO PAULO ZONA SUL', 'SP', '2024-01-15 00:00:00', 'TERCEIRIZADO', 'BEATRIZ APARECIDA DE GODOY GARCIA', 'Aguarda audięncia UNA. Foi para perícia pericul. AEC vai acompanhar a pericia, logo, năo apresentaremos nada. PROCEDENTE. Vamos de ED porque faltou a subsidiariedade no dispositivo. Provido. RO dispensado pela IE 95. TRANSITOU. Zanc intimada p/ pagar. Pagou mas juiz pediu planilha de atualizaçăo. Juiz mandou AEC pagar as diferenças remanescentes e custas. Pagou, aguarda liberaçőes. Rct pediu isençăo do pgto de hon por AgP, năo conhecido. Aidna falta AEC pagar algumas coisas.', 'Resp subs etc', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
