LUES (2500337618, 'FRANCISCO ALEXANDRE SANTOS PEREIRA', 'GERENTE PAA - GERENTE CONTAS PESSOA FISICA I', '2025-04-11 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010513-91.2025.5.15.0136', NULL, 'Paulo Augusto Ferreira - 1Ş Câmara', '01', 'PIRASSUNUNGA', 'SP', '2025-05-06 00:00:00', 'EX-FUNCIONARIOS', 'GABRIEL MOLLER MALHEIROS ', 'Aguarda realizaçăo de audięncia. Juiz ouviu as partes, mas dispensou tests. Aguarda sentença. IMPROCEDENTE. Perdeu cc (nao falou §3ş), he pós 8a, comissőes (pelo tema), VR, PDE e DM. Ed rct, denegado. RO rct.', 'IMPROCEDENTE', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, '400k', 'Ofereci 50k em 28/5. Cobrei em 9/6. Liguei em 24/6, 3/7, 7/7. Oferecido 95k em aud, recusado. Proposta retirada.Voltou como 89k em 21/8. Nao avisei pois ja recusou anterior. Em 9/10, foi para 85k. PROPOSTA RETIRADA', NULL, 'Livia (Camila, pois Livia esta de férias)  - e-mail (31) 2513-0904', NULL, 'ENCERRADO', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
