LUES (2400920793, 'GISELE LOMBARDI MATRICIANO FERREIRA', 'GERENTE RECUPERACAO CREDITO I - GERENTE NEGOCIOS RECUPERACAO C ', '2024-11-13 00:00:00', 'BANCO BRADESCO S.A.', 'BANCO BRADESCARD S.A, BANCO BRADESCO FINANCIAMENTOS S.A E BRADESCO ADMINISTRADORA DE CONSORCIOS LTDA', '0012347-98.2024.5.15.0093', NULL, NULL, '11', 'CAMPINAS', 'SP', '2024-11-22 00:00:00', 'EX-FUNCIONARIOS', 'ANDERSON DE OLIVEIRA BARBOZA ', 'Tem outro processo arquivado. Aguarda realizaçăo de audięncia. Recte năo recolheu as custas do primeiro processo arquivado. Arguimos 844,§3CLT para arquivar por falta de pressuposto, mas juiz rejeitou e mandou seguir. Designou perícia técnica (periculosidade) e médica. Pericul NEGATIVA! Per médica: rct tem Burnout, nexo a depender da instr e sem incapacidade.', '-', 'Vara do Trabalho ', 'BAIXADO ', '2026-03-25 00:00:00', '08:00:00', NULL, NULL, NULL, NULL, 'SAG', '800k', 'Ofereci 50k b em 4/4. Cobrei em 14/4. Liguei em 12/5 e 26/5. Mandou 800k em 3/6. Encerrado. Diminuido p/ 60.200 em 21/8. Retirada no GCPJ.', NULL, 'Anderson - e-mail - Tel: 3239-1467 /', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, 'S', 'S', 'S', NULL, 'S', 'S', NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, 'ADIC. PERICULOSIDADE; EQUIP JORNADA DO TELEMARKETING; DIF. VERBAS RESCISÓRIAS; ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
