LUES (2200677831, 'GLAUCINEIDE DE BRITO OLIVEIRA', 'GERENTE DE CONTAS PESSOA JURÍDICA', '2021-11-25 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011703-57.2021.5.15.0095 - CumPrSe: 0011612-25.2025.5.15.0095', NULL, NULL, '8', 'CAMPINAS', 'SP', '2022-08-18 00:00:00', 'EX-FUNCIONARIOS', 'CELSO FERRAREZE', 'Aguarda realizaçăo de audięncia UNA em 14/09/22. Determinada a realizaçăo de perícia medica. Nexo concausal e incapacidade de 4%. Ouvidas as partes e testemunhas da autora. Designada aud para oitiva por videoconferencia da única testemunha do Banco (Cristiane). PROCEDENTE. Perdeu 7 e 8. RO por ambos. Provido nosso p/ excluir KM e da Autora para aumentar DM de 10 p/ 50k. RR dispensado. Apresentado pela rct, deferido apenas pela aplicaçao da reforma. AIRR pelo restante. CumPrSe: Temos que impugnar calcs rct. Vamos aguardar ela apresentar.', 'IJ (20min), 384 (ate 17), KM, DM (doença - 10k-50k) ', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Liq com hon: 76.963                                        Des 20%: 61.570', NULL, 'Ofereci 50k Liq em 11/7. Só disse q quer mais, mas năo respondeu mais os e-mails', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, 'Sim', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
