LUES (2200911208, 'GUILHERME FORMAGGINI LOPES SILVA', 'ANALISTA SUPORTE OPERACOES JR - ANALISTA  OPERACOES JR - SUPERVISOR ADMINISTRATIVO ', '2022-10-31 00:00:00', 'BANCO BRADESCO FINANCIAMENTOS S.A', '-', '0011704-14.2022.5.15.0093', NULL, NULL, '06', 'CAMPINAS', 'SP', '2022-11-09 00:00:00', 'EX-FUNCIONARIOS', 'NILO DA CUNHA JAMARDO BEIRO', 'Entrou só contra Banco Bradesco Financiamentos, mas a partir de 1/2/20 foi pro Banco Bradesco. ATIVO. Aguarda realizaçăo de UNA. Deferiu tudo. Apresentamos ED, năo providos. RO por ambos. Mantida sentença. ED porque manteve Justiça Gratuita. RR e AIRR por ambos. Denegados, mas ganhou JG. TRANSITOU. Foi direto para perícia. Impugnamos calcs. Rct apresentou petiçăo de RENÚNCIA aos valores ainda năo recebidos (recebeu uns 25k já). Juíza homologou calcs perito e mandou pagar. Questionamos a apreciaçăo da renúncia, juiz mandou rct se manifestar.', '7 e 8, comp grat ok, HÁ (5%), ADC 58', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, 'NAO QUER RESCINDIR', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
