LUES (2400067863, 'GUILHERME HENRIQUE MARTINEZ', 'GERENTE RELACIONAMENTO PRIME - FISICA - GERENTE ASSISTENTE ', '2024-01-26 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010116-81.2024.5.15.0034', NULL, NULL, '01', 'SAO JOAO DA BOA VISTA', 'SP', '2024-01-30 00:00:00', 'EX-FUNCIONARIOS', 'MARCIO ALEXANDRE SILVA GERMINARI ', 'Aguarda realizaçăo de audięncia UNA. PROCEDENTE. Vamos de ED. Rejeitados e aplicada multa. RO por ambos (adesivo rct) (4Ş Câmara). Provido nosso p/ retirar multa e prejudicado do rct. TRANSITOU. Rcd deve apresentar calcs.', '7a e 8a (comp ok), multa ED prot, HA (15%)', 'Vara do Trabalho', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, 'calcs zerados', NULL, NULL, NULL, 'INICIAR', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
