LUES (2400674504, 'IGOR CASAGRANDE', 'GERENTE PAA - SUPERVISOR ADMINISTRATIVO - CAIXA', '2024-08-09 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011350-05.2024.5.15.0065', NULL, NULL, '01', 'TUPA', 'SP', '2024-08-20 00:00:00', 'EX-FUNCIONARIOS', 'ANTONIO ARNALDO ANTUNES RAMOS ', 'Aguarda realizaçăo de audięncia. Na aud, juiz mandou rct juntar provas das ligaçoes de clientes fora do horário em 10 dias. Protestamos. Aguarda INSTR. PROCEDENTE. Perdeu cc, férias, grat caixa, IJ, he, cartoes ok. Vamos de RO. ED pelo Autor, provido p/ esclarecimentos apenas. RO por ambos. Provido nosso p/ presc e diminuir DM trasnp valores (70 p/ 20k). ED pelas tests do rct q nao podiam testemunhar transporte de valores. Nao provido, apenas do rct p/ rejeitar RO condicionado. RR dispensado. RR rct. CRRR ja na pasta (feito em jan)', 'PLR, DM (transp valores - 20k) e DM (metas - 30k)', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'PPS               b+h: 62.457          L+H: 58.457', '350k ', 'Ofereci 40k b em 22/01. Cobrei em 29/1. Querem 350k, encerrei. Em 14/02 Banco baixou de 67 p/ 19. Em 19/2 passei novo valor. SENTENÇA de 131.881. Ofereci 80k (b=l) em 8/4. ACORDAO. Ofereci 44k liq em 10/12. Cobrei em 12/12. Quer decisao TST.', NULL, 'e-mail', 'n', 'ENCERRADO', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', 'S', NULL, NULL, NULL, 'S', NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Garttificaçăo de caixa', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
