LUES (2500928905, 'IRAINA MUNHOZ RODRIGUES DE OLIVEIRA', 'GERENTE INVESTIMENTOS - COORDENADOR INVESTIMENTOS - ESPECIALISTA INVESTIMENTOS II', '2025-11-10 00:00:00', 'BANCO BRADESCO S.A.', '-', '0012377-58.2025.5.15.0042', NULL, NULL, '02', 'RIBEIRAO PRETO', 'SP', '2025-11-12 00:00:00', 'EX-FUNCIONARIOS', 'EVANDRO PREDEVELLO', 'Aguarda realizaçăo de audięncia. Íamos apresentar exc incomp pq a Reclamante estava lotada em Cps, mas ela trabalhava externamente, inclusive em Ribeirăo, entao melhor deixar assim pois já prova que a jornada năo era controlada. ', '-', 'Vara do Trabalho ', 'BAIXADA', '2026-02-20 00:00:00', '16:20:00', NULL, NULL, NULL, NULL, '250k', '500k', 'Ofereci 120k b em 22/01/26. Cobrei em 27/1. Liguei em 2/2 e 3/2, mas nao atendeu. Mandei wpp, nada. Em 4/2 ligui pro sócio do esc e a Michele me mandou msg na hora. Quer 500k.', NULL, 'Jaqueline - PTZ Uberlandia', NULL, 'Encerrado', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', NULL, NULL, 'S', NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, 'S', NULL, NULL, NULL, 'MULTA 477; Programa de Incentivo de Longo Prazo; reajuste salarial pela categoria', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
