LUES (2200167684, 'IRENE MIRANDA DE CALDAS', 'SUPERVISOR ADMINISTRATIVO ', '2021-12-12 00:00:00', 'BANCO BRADESCO S.A.', '-', '0012895-79.2021.5.15.0077', NULL, NULL, '1', 'INDAIATUBA', 'SP', NULL, 'EX-FUNCIONARIOS', 'LUIZ MIGUEL ROCIA', 'Aguarda realizaçăo de audięncia UNA em 16/08/22. INSTR para 9/3/23. PROCEDENTE. Deu horários de entrada do cartao, ij em 2 dias na semana e saida ok em 2 dias também. Indeferiu intergr VA e VR. Reforma ok. Vamos de RO. Adesivo pela Autora. Năo providos. RR por ambos. Negado prov ao da rct. Nosso deferiu, mas na conclusao negou. Vamos de ED. Acolhidos. Aguarda julgamento do RR. ', '7a e 8a (sem comp), IJ e he extra ponto em 3 dias na semana, 384, HÁ (10) e JG', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, '350k', 'Ofereci 100k liq+ 20 hon em 16/9. Advogada disse que pedirá calcs. Aguardamos. Nunca retornou  ', NULL, 'Nicoli wpp (11) 91340-3628 ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
