LUES (7215175, 'ISABEL CRISTINA MARINO LONGATO ', NULL, NULL, NULL, NULL, '0171700-69.2000.5.15.0012', NULL, NULL, '01', 'PIRACICABA', 'SP', '2025-03-27 00:00:00', 'EX-FUNCIONARIOS', NULL, 'Processo físico. Pelas infos do GCPJ, a rct foi reintegrada pq anularam a justa causa (tinha sido pq ela estava inadimplente). Parecer do Pellegrina disse que foi por causa de doença. Acordao fala em desproporçăo da JC pq as irregularidades nao foram alegadas pelo banco e nao sao habeis p/ justa causa. Nao fala nada de doença. Ainda tento encontrar alguma coisa no TRT 15 para esclarecer. Pedi infos ao RH do BAnco tb. Achei o num do PJE em 5/8/25. Lá a rct pediu, em 12/2022, que o Banco Mercantil corrija seu Cnis para que ela possa pedir a aposentadoria. MAndou rcd se manifestar em 30 dias. Pellegrina se habilitou e e pediu, em 6/23, que digitalizassem os autos ou desse mais prazo. Em 12/23 adv rct disse que os autos estavam em secretaria física. Em 8/24, Firmino mandou as partes digitalizarem os autos. Desde entăo Pellegrina pede 10 dias, nao faz nada e o juiz defere mais 10 dias. Pegamos as cópias. REINTEGRADA em 22/01/2003.  ', '-', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
