LUES (2300492883, 'ISABEL GONCALVES DA SILVA', 'GERENTE CONTAS PESSOA FISICA - GERENTE PAB ', '2023-06-13 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010920-82.2023.5.15.0099', NULL, 'Thelma Helena Monteiro de Toledo Vieira - 9Ş Câmara ', '02', 'AMERICANA', 'SP', '2023-06-16 00:00:00', 'EX-FUNCIONARIOS', 'CELSO FERRAREZE ', 'Verba de representaçăo. Aguarda realizaçăo de audięncia UNA. Juiz dispensou oitiva das partes e estava ouvindo a 1 test da Autora, quando teve problema de comexao. Aguarda remarcaçăo. PROCEDENTE. Perdeu VR. RO por ambas.  ', 'IMPROCEDENTE', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, '60.000/226.427,78/ ZERO/ 140.100 / 123.300/ ZERO', 300000, 'Mandei 120k bruto em 21/8/23, cobrei em 11/9, 14/9. Em 220k  em 2/10. Mantive o valor mesmo após o banco retirar a proposta do outro porque vai quitar os 2 mesmo. Mandei 180k em 24/10. Cobrei em 1/11, 5/3/24. Em audięncia pretende 600k. Em 8/11, banco mandou nova proposta (que soma 280k, mas nem ofereci pois muito distantes ainda dos 600k. Em 14/02 Banco baixou mais ainda, mas tb nao avisei pela distancia. eM 28/7/25, Banco RETITOU a proposta desse, mantendo apenas a de 71k.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
