LUES (1200044376, 'JEAN SENA SCUIRA', 'GERENTE ADMINISTRATIVO', '2012-01-30 00:00:00', 'JD.LONDRES-UCAMPINAS', '-', '0000138-14.2012.5.15.0095   - 0011148-50.2015.5.15.0095 - 1000663-09.2020.5.00.0000', NULL, NULL, '8', 'CAMPINAS', 'SP', NULL, 'EX-FUNCIONARIOS', 'CELSO FERRAREZE', 'Conhecimento: ja trasnitou, inclusive ja baixou do TST. Exe Prov (que ja virou def, mas segue nos autos da prov: Homologou cálculos do perito. Garantimos e apresentamos EE, quando nossos novos cálculos foram homologados. Recursais nă abatidos. Autor apresentou AP, que foi provido em parte. Banco apresentou RR contra IPCA. Valor incontroverso já depositado mas nao levantado. Aguarda julgamento do RR em AP. Ministro denegou substituiçăo da garantia. Apresentei pedido de reconsideraçăo. Reconsiderou em parte, mandando para a execuçăo decidir. Vou desistir pois valor abaixo de 500k.  Pedi STF. SUSPENDEU O processo até julgamento pelo pleno do TST da inconstitucionalidade do §7 do art. 879 da CLT. Exe prov foi trasnformada em Cumprimento de sentença e lá seguirá a execuçăo. TRANSITOU. Cálculos foram atualizados e estavam corretos, sem matéria para EE. Aguardamos as liberaçoes. Autor apresentou ISL, acolhidas. Sem matéria p/ AP (Milena). Vamos pagar a diferença e arquivar. Há depósitos suficientes, pedimos a liberaçăo e o retorno do excedente.  ', 'Inserir', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 280780, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
