LUES (2400624980, 'LUCAS MANFREDO GARCIA', 'GERENTE ASSISTENTE - CAIXA', '2024-08-01 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011263-89.2024.5.15.0084', NULL, 'José Otávio de Souza Ferreira - 2Ş Câmara ', '04', 'SAO JOSE DOS CAMPOS', 'SP', '2024-08-05 00:00:00', 'EX-FUNCIONARIOS', 'IVAN JOSE SILVA', 'Aguarda realizaçăo de audięncia UNA. Sentença PROCEDENTE. Perdeu PLR e indeniz Subst. do SD. Vamos de ED, pois juiz determinou expediçăo guias SD (năo leu a defesa com a CTPS). Rejeitados + multa. RO por ambos (do rct pela PLR 23).ATENÇĂO: Seremos notificados após TJ para retificar data dispensa rcte e comprovar depósitos FGTS+40%', 'Convolaçao da Justa Causa; verbas resc. (todas, sem deduçăo do que foi pago); obrigaçăo de fazer: anotaçăo CTPS após TJ (seremos notificados); comprovar FGTS +40% e expedir guia SD', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, 'processado');
