LUES (2100785226, 'LUCAS NOVAES DA COSTA', 'GERENTE ASSISTENTE', '2021-07-30 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010846-94.2021.5.15.0132', NULL, NULL, '5', 'SAO JOSE DOS CAMPOS', 'SP', NULL, 'EX-FUNCIONARIOS', 'SABRINA NOVAES DA COSTA ', 'Aguarda realizaçăo de Audięncia UNA em 7/4/22. Sentença procedęncia, que rejeitou apenas desvio. Vamos de ED porque nada falou sobre a compensaçăo da gratificaçăo. Năo aceitaram. RO pelas partes. RO do Banco provido para reconhecer a negativa de prestaçăo, anular a sentença de ED e mandou voltar para que seja apreciado o pedido de compensaçao de grat. Juiz indeferiu o pedido. Vamos apresentar novo RO. Autor apresentou adesivo. Provido do Autor para majorar DM de 3 para 15 e do Banco para autorizar a comp da gart fun, juros e refle nos DRS. RR dispensado. ED pelo Autor, nao provido. RR do Autor denegado. TRANSITOU. Partes apresentaram calcs. Foi para perícia. Impugnamos. Homologados do perito. Apresentamos EE. ', 'HE após 6Ş, comps ok, DM (15k), HÁ e ADC + juros 1%', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Ultim cals: 8/25                          B+h: 151.178                                L+h:  143.708                        ', '130k liquido + 20H', 'Calcs homol per: 138.332                                           Calcs banco: 101.984                                                         Ofereci 105 L + 15 H em 4/9. Cobrei em 9/9, 12/9. O máximo que chegaremos será o valor de 143.700, sendo 122.200 liq + 21.500 de honorários. Na aud de 9/25, Rct quis 8k a mais e nao fechou por isso.        ', NULL, 'wpp Sabrina', NULL, 'ENCERRADO', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'processado');
