LUES (2100762758, 'LUIZ CARLOS CASARI JUNIOR', 'VIGILANTE', '2021-10-05 00:00:00', 'GP GUARDA PATRIMONIAL', 'BANCO BRADESCO S.A.', '0011518-89.2021.5.15.0007', NULL, NULL, '1', 'AMERICANA', 'SP', NULL, 'TERCEIRIZADO', 'FRANCISCO TADEU MURBACH ', 'Aguarda realizacao de audięncia de INICIAL em 19/11/21. GP năo citada, CONC para 24/02/22. Aguarda INSTR em 27/522. Procedente. RO pela GP apenas, năo provido. RR pela GP, năo conhecido por deserto. TRANSITOU. Determinada apresentaçao de cálculos pela GP, nao apresentou. Banco apresentou e foram homologados. Determinado pgt pela GP. Indicou bens e opôs EE. Nao acolhidos por falta de garantia. Apresentou AP tb nao conhecido. AI em AP, nao conhecido pela falta de garantia. Em vista da ausęncia de pgt e/ou garantia, mandou o banco pagar. Pedimos os calculos, mas ai GP apresentou AIAP e o juiz reconsiderou o redirecionamento da execuçao. AIAP denegado. RR e AIRR pela GP. Aguarda realizaçăo de audięncia INICIAL.PROCEDENTE. ED pelo Autor, năo provido. RO por ambos. Denegado. RR e AIRR pela GP, denegados. Voltou ŕ Vara, pediram bacen na GP. Negativo. Fomos intimados a pagar. Pagamos. Denúncia de que FGTS estava a menor.', 'Resp subs, etc', 'Vara do Trabalho', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
