LUES (2200562629, 'MANOEL BEZERRA DA SILVA', 'VIGILANTE', '2022-06-30 00:00:00', 'GOCIL SERVICOS DE VIGILANCIA E SEGURANCA LTDA', 'BANCO BRADESCO S.A. + 1', '0011575-40.2022.5.15.0018', NULL, NULL, '1', 'ITU', 'SP', NULL, 'TERCEIRIZADO', 'FABIANO SAMPAIO AVILA D ALOIA', 'Aguarda realizacao de audięncia de UNA em 29/08/23. Procedente em parte. RO dispensado. ED pela Gocil, năo provido. RO pela Gocil. RR dispensado. TRANSITOU. Reclamadas devem apresentar cálculos. Gocil năo respondeu, entao pedimos cálculos. Apresentamos e a idiota da Gocil tb. Autor concordou com a da Gocil. Juiz mandou ele separar os períodos de resp de cada tomador. Foi pra perícia, todos concordaram com o laudo. Homologado. Mandou pagar. Gocil pagou as extraconcursais (INSS e hon). Zaraplast quitou toda sua parte. Temos que pagar o remanescente da nossa. O crédito restante irá p/ RJ. ', 'Resp subs etc', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
