LUES (2100039438, 'MARCO AURELIO DOS SANTOS LINARES', 'VIGILANTE', '2021-01-19 00:00:00', 'GP GUARDA PATRIMONIAL', 'BANCO BRADESCO S.A.', '0010049-94.2021.5.15.0043 - CumpSen: 0011927-83.2023.5.15.0043 ', NULL, NULL, '3', 'CAMPINAS', 'SP', NULL, 'TERCEIRIZADO', 'BRUNO ARAUJO ALFARO', 'Determinada apresentaçăo de contestaçăo em 15 dias (25/02). INSTR para 4/4/23.Rct ausente na audięncia. Procedente em (grande) parte. RO por todos. RR dispensado, mas apresentado pela GP e Autor. Marcaram CONC, năo frutifera. RR e AIRR por ambos. Denegados. TRANSITOU. Deps recursais serao trasnferidos p/ CunSen. Cump Sent: rés devem se manifestar aos cálculos do Autor. GP fez isso. Homolo calcs do Autor. GP intimada para pagar. Garantiu e apresentou EE.Rejeitado. AP tb. AIAP pela Gocil. Indeferida a exe sobre o Banco pq Gocil garantiu o processo. Aguarda julgamento de AIAP da Gocil. ', 'Resp subs etc', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
