LUES (1800055335, 'MARCOS ANTONIO CERON', 'ATENDENTE DE AGENCIA', '2017-10-19 00:00:00', 'BANCO BRADESCO S.A.', '-', '0012218-89.2017.5.15.0012', NULL, NULL, '1', 'PIRACICABA', 'SP', NULL, 'EX-FUNCIONARIOS', 'VALDOMIRO VIEIRA BRANCO FILHO', 'Laudo pericial atestou ausencia de nexo de causalidade e capacidade laboral integral e preservada. Determinada realizaçăo de nova perícia em 10/9. Segundo laudo positivo para doença. Impugnamos e em 5/7/21 apresentei impugnaçăo aos esclarecimentos e pedi prova oral.  INSTR para 1/2/22. Juiz indeferiu as provas orais, dipendo que eram apenas documentais. Instruçăo encerrada sob protestos. Anta da patricia nao pediu pz para RF. Sentença procedęncia. Fomos de ED, improvidos. RO normal e complementar após sentença de ED do rct. Aguarda julgamento dos ROs das partes. Provido apenas para aplicar o redutor. ED pelo Russo. Nao provido. RR e AIRR pelo Banco. Denegados. Agravo pelo banco.', 'Doença laboral, D mat: 150k por reduçăo de 30% na capacidade desde o afastamento prev de 2005; D moral: 15k ', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
