LUES (2000565379, 'MARIANA FARIAS FONSECA', 'OPERADOR DE TELEATENDIMENTO', '2020-10-06 00:00:00', 'CHAIN SERVICOS E CONTACT CENTER S.A.', 'ALMAVIVA + BRADESCO', '0011471-19.2020.5.15.0018', NULL, NULL, '1', 'ITU', 'SP', NULL, 'TERCEIRIZADO', 'VIVIANE PIASSI', 'Determinada apresentaçăo de defesa em 15 dias (P:23/10). UNA em 30/07/21. Sentença parcialmente procedente. RO pela Chain e Autora, apenas dessa última provido pra aumentar valor DM. Russo apresentou ED, provido parcialmente. RR dispensado por Eduardo. Nao conhecido o da Chain, quie ainda apresentou AI e Agravo, todos desprovidos. RecExt pela Chain, denegado. TRANSITOU. Homologados cálculos da Chain, intimada p/ pagar.', 'Resp Subs, DM (doença - 5k), reconhecimento rescisăo indireta', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
