LUES (2200137702, 'MARIANA GINEZZI RIBEIRO', 'GERENTE DE CONTAS PESSOA JURÍDICA ', '2022-02-21 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010174-55.2022.5.15.0034 -  EXE PROV: 0011724-17.2024.5.15.0034 ', NULL, NULL, 'PAJT ESPIRITO SANTO DO PINHAL', 'SAO JOAO DA BOA VISTA', 'SP', NULL, 'EX-FUNCIONARIOS', 'APARECIDO RODRIGUES ', 'Aguarda realizaçăo de audięncia UNA em 19/10/22. Procedente. Autora apresentou ED, năo provido. RO pelas partes. Provido do banco para aplicar a reforma, a compensaçao da grat e hon advogado. Da Autora para dar IJ. RR dispensado. RR pela Autora, recebido parcialmente apenas para tratar da aplicaçao da reforma. AIRR pela Autora. EXE PROV: Temos que impugnar os cálculos. Mandou p/ perícia.   ', 'HE após 6, treinet, jornada das 8h as 18h30, IJ, multas CCT, HÁ (15) e ADC 58', 'TST/ Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 262355, '230+34', 'Com AIRR da Autora. Ofereci 200k Liq em 5/3. Cobrei em 15/3 e 1/4. RENOVEI EM 19/6. E de novo em 11/7. Querem 264 (230 + 34). Ofereci o max de 230k liq no total em 10/9, năo quer. Pedi calcs atual. Pet no TST oferecendo 218.500 (190+ 28.500) em 14/4', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', 'Sim', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
