LUES (2200389717, 'MARIANA MARTINS MOREIRA', 'GERENTE ADMINISTRATIVO ', '2021-04-07 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010467-65.2021.5.15.0032', NULL, NULL, '2', 'CAMPINAS', 'SP', NULL, 'EX-FUNCIONARIOS', 'ALAN HONJOYA', 'Aguarda realizaçăo de audięncia INICIAL em 25/8/22. CANCELADA. Determinada apresentaçăo de defesa em 15 dias (29/7). Marcada UNA. Foi pra perícia. NEGATIVA. Aguarda  INSTR. PROCEDENTE. Perdeu cargo de confiança, IJ, cartoes ok,  perdeu doença, dm dips pandemia.  Silenciou sobre as matérias da outra açăo, e como declarou a presc 5nal, nao falaremos nada, vamos de RO direto pela JG e hon adv. Rct foi de ED, mas nao pediram a apreciaçăo dos pedidos da outra açăo. Rejeitados. RO pelas partes. Ambos providos p/ detalhes. RR dispensado. ED da rct, rejeitado. RR e AIRR rct.', 'I 384, HÁ(15)', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, 'Cálculos estao em 2.500. Rct pediu 60k. Encerrado', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'Sim', 'Sim', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
