LUES (2400853449, 'NATHALIA APARECIDA DE OLIVEIRA', 'GERENTE DE CONTAS PESSOA JURÍDICA - GERENTE DE PAB - GERENTE DE CONTAS PESSOA FÍSICA  ', '2024-10-10 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011759-37.2024.5.15.0014', NULL, NULL, '01', 'LIMEIRA', 'SP', '2024-10-18 00:00:00', 'EX-FUNCIONARIOS', 'BRUNO CABRAL PACHECO', 'Aguarda realizaçăo de audięncia - processo anterior arquivado por ausęncia na 1 aud, ajuizou novamente açăo idęntica. LAUDO NEGATIVO! PROCEDNETE. Perdeu cc, IJ, dm, doença e tudo dela decorrente. ED pelo Banco, năo providos. Vamos de RO. Teve novo ED pelo rcte após sentença de ED. Providos p/ prescriçăo. RO por ambos (11Ş Câm -Luis Henrique Rafael). ', 'Equip, VR, atraso promo, PLR', 'TRT', 'N', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, ' (195)Ofereci 100k em 6/3. Perguntou quanto eu subiria. Pedi a contraproposta. Cobrei em 10/3, 12/3, 17/3, 20/3, 9/6, 7/7. Nunca respondeu. Liguei só caixa postal. Em 17/7 mandei wpp, só disse que năo. ATENCAO laudo negativo. Proposta retirada em 6/8. SENTENÇA. Calc banco: 147k. Ofereci 100k b em 8/12. Disse q era pouco. Pedi cpp (pelo jeito é um tapadao). Insisti em 20/01/26, 23/2', NULL, 'e-mail Bruno - cel (62) 98100-2177', NULL, 'AGUARDA RESPOSTA', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
