LUES (2400013853, 'NATHALIA CRISTINA CONTATO', 'GERENTE CONTAS PESSOA FISICA; GERENTE CONTAS PESSOA JURIDICA', '2023-12-07 00:00:00', 'BANCO BRADESCO S/A', 'BRADESCO VIDA E PREVIDĘNCIA S.A. e BRADESCO SEGUROS S.A.', '1001788-72.2023.5.02.0704', NULL, NULL, '04', 'SAO PAULO ZONA SUL', 'SP', '2024-01-10 00:00:00', 'EX-FUNCIONARIOS', 'FERNANDA AMARO LIMA ', 'Aguarda audięncia UNA. Foi para perícia. Aguarda INSTR. Cartoes ok. Perdeu comissoes, he, doença (nao provou ambiente toxico) e estabilidade. Vamos de RO pela resp sol, JG e PLR. Năo provido. RR dispensado contra nossa orientaçăo. RR e AIRR rct.', 'PLR prop (contra a CCT), resp sol', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'B+h: 4.969                          L+h: 7.729,70', NULL, NULL, NULL, NULL, NULL, 'INICIAR', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
