LUES (2100829513, 'NATHALIE MARIN AMOROSO DA SILVA', 'CAIXA', '2021-11-05 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011676-07.2021.5.15.0085', NULL, NULL, '1', 'SALTO', 'SP', NULL, 'EX-FUNCIONARIOS', 'FABIO ROBERTO BISCA  ', 'Determinada apresentaçăo de defesa em 15 dias (07/12). Aguarda INSTR. PROCEDENTE. Perdeu desvio e dm. RO dispensado pela IE 95. ED pela Autora, rejeitados. RO da Reclamante, năo provido. RR dispensado. ED da rct, nao provido. RR e AIRR rct.', 'IJ 15 e há (10%)', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'PPS                             B+H= 18k                     L+H= 17.550', NULL, 'Pedi pretensao e mandaram o valor da causa (86 L).  Mandei 6k L com hon. Năo aceitou. Em 17/11, mandou e-mail dizendo que aceitava 65k. Respondi em 22/11 que o banco mantem os 6L. ACORDAO. Ofereci 14.800 em 10/12. Manteve os 65k. Mandei passear.', NULL, NULL, 'n', 'Encerrado', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
