LUES (2200348543, 'OSVALDO DAVID MIRANDA NETO', 'VIGILANTE', '2022-04-29 00:00:00', 'GP GUARDA PATRIMONIAL', 'BANCO BRADESCO S.A.', '0010830-54.2021.5.15.0096', NULL, NULL, '3', 'JUNDIAI', 'SP', NULL, 'TERCEIRIZADO', 'MATHEUS DE ALMEIDA ALVES', 'Aguarda realizaçăo de audięncia INICIAL em 19/5/22. Aguarda marcar INSTR. Procedente. ED por nós e rct, acolhidos. Vamos de RO pela execuçăo. RO do Autor. Suspenso até decisao do IRDR 2 (oposicao desc sindical). A pedido, desembargador mandou abrir outros autos p/ julgamento parcial, a fim de julgar tudo, menos o tema suspenso. ', 'Resp subs etc', 'TRT', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
