LUES (2500091459, 'PAOLA DE OLIVEIRA MANTOVANI', 'GERENTE ASSISTENTE - GERENTE CONTAS PESSOA FISICA  ', '2025-02-05 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010186-89.2025.5.15.0058', NULL, NULL, '01', 'BARRETOS', 'SP', '2025-02-06 00:00:00', 'EX-FUNCIONARIOS', 'ERALDO LOPES SILVA JUNIOR ', 'Apresentada exceçăo de incomp. Pediram p/ juntarmos o contrato de trabalho, mas disse q năo tem. Acolhida exceçăo, será enviada a Barretos. Aguarda realizaçăo de audięncia.', '-', 'Vara do Trabalho ', 'PENDENTE', '2026-08-31 00:00:00', '15:30:00', NULL, NULL, NULL, NULL, '200k', '520k/260k/230', '(160)Ofereci 100k em 6/3. 125k em 7/3. Nao aceitou. Retirada em 6/8. Eraldo avisado. Voltou MT 90 com 120k. Ofereci 120k em 5/9. Em 1/12, com nova alçada GCPJ, mandei 150k (IJ 100k, PDE 300, DM 20). 200k Liq em 8/12. Ta enrolando. Indiquei p/ conciliaçao', NULL, 'Eraldo wpp', NULL, 'Aguarda resposta', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', NULL, NULL, NULL, NULL, NULL, 'S', NULL, 'S', NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, 'S', NULL, 'S', NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
