LUES (2200595359, 'RICARDO SMANIOTTO', 'SUPERVISOR ADMINISTRATIVO II', '2022-07-13 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011037-62.2022.5.15.0114', NULL, NULL, '9', 'CAMPINAS', 'SP', NULL, 'EX-FUNCIONARIOS', 'JOSIEL VACISKI BARBOSA', 'Aguarda realizaçăo de audięncia UNA em 14/03/2023. Aceitaram nossa tese da interrp há mais de 5 anos, negaram verba de representaçăo, integr VR e VE e 7 e 8. Reconheceu cartoes, mas disse q ele logrou apontar he, ai deferiu isso. RO por ambos, provido apenas do Banco para afastar as dif de horas extras e julgar o processo IMPROCEDENTE. ED do Autor, nao provido. RR e AIRR pelo Autor, dengados. Agravo. Năo provido e multa de 2% a favor do Banco. Agravo na SDI, denegado. TRANSITOU. TM reserva. Aguarda pto multa 2% ao banco pelo rct.', 'Dif de horas extras năo pagas - IMPROCEDENTE', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
