LUES (2400070457, 'RODRIGO TAKASE RODRIGUES LOURENCO', 'GERENTE ASSISTENTE PA - SUPERVISOR ADMINISTRATIVO - CAIXA', '2024-01-12 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010019-60.2024.5.15.0041', NULL, NULL, '01', 'ITAPETININGA', 'SP', '2024-02-01 00:00:00', 'EX-FUNCIONARIOS', 'NILO DA CUNHA JAMARDO BEIRO', 'Aguarda realizaçăo de audięncia UNA. PROCEDENTE. Perdeu acumulo/desvio, km, cartoes ok. ED das partes năo providos. RO por ambos. Privido do Autor p/ correçăo. Nosso p/ limitar IJ, diminuir ind de 15k para 10k. Apresentei  ED pelo par 3 e 1. Denegado. RR dispensado pelo Banco. RR rct.', 'Sal subs (37 dias), He pos 6, comp ok, IJ (4 a 12/2020), e Hon advogado, dm (assedio - 10k)', 'TRT', 'N/D', '2025-11-06 00:00:00', 'N/D', NULL, NULL, NULL, NULL, '29K B', NULL, 'Rel enviado em 22/10. Reclamante tem outra açăo nova que está com o Perez e pede reintegraçăo (sem alçada). Ofereci 29k b já com hono na audięncia , năo aceita.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, 'S', NULL, 'S', 'S', NULL, NULL, NULL, NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, 'S', 'S', NULL, NULL, NULL, 'S', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
