LUES (1800439401, 'ROGERIO DE CARVALHO VARGAS - Vara năo', 'GERENTE AGENCIA', '2018-06-27 00:00:00', 'BANCO BRADESCO S.A.', '-', '0010652-37.2018.5.15.0088', NULL, NULL, '1', 'LORENA', 'SP', NULL, 'EX-FUNCIONARIOS', 'CELSO FERRAREZE', 'Condenado apenas em reflexo da cesta alimentaçăo. Banco năo apresentou RO. RO do Autor provido em parte para determinar pgto integral do PLR com desconto do já pago, JG, suspensăo HÁ por 2 anos, IPCA. Banco apresentou ED sobre IPCA e Reclamante RR (tudo). ED improvido. Banco apresentou RR pela correçăo e Autor AI, que aguardam julgamento', 'Reflexo de cesta alim no AP, PLR, HÁ e IPCA', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, '11.300 - relatorio (tudo ind)', '80k/ 22,5k a pretensao', 'Re ofereceu 6k bruto em 19/7. Quer 80k. Aguarda atualizados. Ofereci 9k em 4/12 e se disserem que aceitam ou fizerem contraproposta razoável, peço nova autorizaçao. Apresentou em audięncia contraproposta de 21k + 5% de honorários, informou que em acordăo o juros fixado foi o IPCA-e . Em 18/2 Ana ofereceu 11.300 b=l. Reiterei em 18/3.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'processado');
