LUES (1700597048, 'TATIANA PAGAN BRUSCHINI - Vara năo', 'GERENTE AGENCIA', '2017-09-11 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011019-05.2017.5.15.0118', NULL, NULL, '1', 'ITAPIRA', 'SP', NULL, 'EX-FUNCIONARIOS', 'NILO DA CUNHA JAMARDO BEIRO', 'Aguarda julgamento dos ROs no TRT. Processo SUSPENSO até decisăo do recurso repetitivo sobre reflexo de DSR e validade da cláusula da CCT que exclui PLR proporcional. Reclamante alegou que năo tem essas materias no recurso. TRT acolheu e mandou por o processo em pauta. Banco nao recorreu dos HA 20%. TRT nao acolheu nosso RO, só da Autora para deferir  add por acumulo, IJ e interrupçăo da prescriçăo. ED pela Autora, desprovidos. RR da Autora e Banco denegados. AIRR por ambos, nao providos. Agravo pela Autora (juros na Selic e he pós 6a quando ger contas) .', 'Horas extras após 8a, PLR 2016 HSBC,  Interrup prescr; add de funçăo; IJ; HÁ sindicato 15%  (ED) e IPCA', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Bru c/ hon: 761.130                                                           Liq c/ hon: 704.630                      Ofereci                                                        ', '900k/  690k', 'Ofereci 550k liq em 15/7 (460 rcmt + 90 ha). Cobrei em 22/7. Depois em 6/8 e em 4/9. Querem 900k. Mandei 650k liq em 10/9. Ela baixou pra 690. Mandei 680k em 13/9. Quer 690k. Sim, recusou pelos 10k. Com PPS, mandei 700k L em 16/4/25. ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Sim', NULL, NULL, 'Sim', NULL, 'Sim', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
