LUES (2000720022, 'THAIS DO NASCIMENTO OLIVEIRA', 'OPERADOR DE TELEATENDIMENTO', '2020-09-28 00:00:00', 'CHAIN SERVICOS E CONTACT CENTER S.A.', 'ALMAVIVA + BRADESCO', '0011872-18.2020.5.15.0018', NULL, NULL, '1', 'ITU', 'SP', NULL, 'TERCEIRIZADO', 'VIVIANE PIASSI', 'Determinada apresentaçăo de defesa em 15 dias. UNA para 22/11/21. Năo foi na perícia médica 2x e juizz declarou a prova preclusa. Sentença procedęncia. RO pelas 3 partes, provido do Banco pra afastar Sintratel e danos morais. RR dispensado. RR e AI pela Chain, denegado. Apresentaram agravo, denegado e imposta multa de 2%. RE pela Chain, nao admitido. TRANSITOU. Calculos homologaods, Chain irá pagar. Nao pagou, bloquearam. Vao liberar recursal do banco e arquivar.', 'Resp subs etc', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
