LUES (2000097924, 'TIAGO BATISTA DOS SANTOS', 'VIGILANTE', '2020-01-31 00:00:00', 'SERVICO ESP DE SEGURANCA VIG INT SESVI DE S PAULO LTDA', 'BANCO BRADESCO S.A.', '0010127-49.2020.5.15.0132 (arq) - CumpSen 0011353-21.2022.5.15.0132', NULL, NULL, '5', 'SAO JOSE DOS CAMPOS', 'SP', NULL, 'TERCEIRIZADO', 'FATIMA APARECIDA DOS SANTOS', ',Aguarda realizaçăo de audięncia UNA no dia 29/04/20. CANCELADA. Recebida a defesa do banco e autor deverá indicar endereço para citaçăo da Sesvi. UNA para 03/09/21. Sentença procedencia. Apresentamos ED. Improvido. RO pelo Banco. RR pelo Banco, denegado. Fomos AIRR. Russo desitiu do AIRR e TRANSITOU. Exe segue nos autos de cumpr de sentença, onde impugnamos os calculos do Autor e depoistamos o incontroverso. Pela divergęncia, foi para perito. Concordamos com os cálculos do perito. Homologado. Sesvi intimada para pagar. Nao pagou, mas tinha 59k depositado por ela em 4/24 e liberaram. Farăo bacen contra ela pelos 5,3k restantes.  ', 'Resp subs, VRs, 467 e 477; Vale -ref, cesta basica, entrega de PPP, ASO e LCAT, PLR, dobra das férias, FGTS + 40%, HÁ e ADC 58 + 1%', 'Vara do Trabalho ', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
