LUES (2100700406, 'VANIA DA SILVA PINTO', 'GERENTE NEGOCIOS RECUPERACAO C', '2021-09-17 00:00:00', 'BANCO BRADESCO S.A.', '-', '0011271-67.2021.5.15.0053', NULL, NULL, '4', 'CAMPINAS', 'SP', NULL, 'EX-FUNCIONARIOS', 'JOSIEL VACISKI BARBOSA', 'Aguarda realizaçăo de audięncia UNA para 28/06/22. Sentença parcial. ED pelos honorários. RO do banco năo provido e da Autora provido parcialmente. Perdeu só 7 e 8. ED pelo russo, năo provido. RR pelo Banco (384, integr aux ref, correçao (năo sei porque) e pela Autora. Do banco recebido parcialmente, da Autora nao recebido. AIRR por ambas.', 'Afastou a HE em eventos, dif de add noturno, 384 (sem limitaçao), integr aux ali,  susp da prescri da 14010,  PLR, km, IPCA + 1%, HÁ (15) ', 'TST', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, 'Brt=liq c/ hon: 136.300            ', '350k', 'Ofereci 80k bruto em 5/10. Rafa disse que năo fez os calculos, entao năo tem proposta. Pedi atual em 4/25. ok. Ofereci 100k liq por pet no TST (85+15) em 24/4. Quer 315+15%', NULL, NULL, NULL, 'Encerrado - mas ta com pet no TST', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
