LUES (2200549621, 'VITOR DE SOUZA GARCIA', 'ANALISTA CANAIS DIGITAIS JR', '2022-06-29 00:00:00', 'BANCO BRADESCO S.A.', '-', '1000863-06.2022.5.02.0383', NULL, NULL, '3', 'OSASCO', 'SP', NULL, 'EX-FUNCIONARIOS', 'MURILO MAXIMO RODRIGUES', 'Aguarda realizaçăo de audięncia UNA em 09/11/2022. Sentença parcial. Aceitou nossa tese de que apresentou  protesto 5 anos após 2016. RO pelas partes. Năo providos. RR por ambos, denegados. Russo năo respondeu nosso e-mail informando se iriam apresentar AIRR ou nao, entao, nao apresentamos. AIRR pelo Autor. Russo nao quis AIRR adesivo. Denegado. TRANSITOU. Vamos manifestar aos calcs rct. Pela diferença, foi para perícia. Calcs perito homologados. Mandou liberar recursais, atualizar saldo remanescente e depois vamos ser citados para pagar. Sem matéria p/ EE (calcs perito quase metade dos nossos).', 'HE após 6, comp a partir de 9/2018', 'Vara do Trabalho', 'N/D', 'N/D', 'N/D', NULL, NULL, NULL, NULL, '59.655 (20% menos que os calculos a condenaçao sem atual ainda)', '250k', 'Ofereci 45k Liq em 14/8 por email. Cobrei em 23/8. 60k em 30/8. Quer 250k ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Processado');
